domain_model:
{
  "domainKit": {
    "name": "School Management",
    "packageBase": "com.application.school",
    "coreDomains": [
      {
        "name": "Student",
        "description": "Gestiona la información académica y personal del alumno.",
        "entities": [
          {
            "name": "Student",
            "attributes": ["studentId", "legalId", "firstName", "lastName", "dateOfBirth", "enrollmentDate", "status (ACTIVE, INACTIVE, GRADUATED)"],
            "businessRules": ["El studentId se genera automáticamente al matricularse.", "Un alumno no puede tener más de un registro activo con el mismo legalId."]
          },
          {
            "name": "Guardian",
            "attributes": ["guardianId", "firstName", "lastName", "email", "phoneNumber", "relationship"],
            "businessRules": ["Un alumno debe tener al menos un tutor/contacto registrado."]
          }
        ],
        "relationships": ["Student (1) --- (*) Guardian (Muchos a Muchos, con atributo de relación)"]
      },
      {
        "name": "Attendance",
        "description": "Control de la asistencia diaria de los alumnos a clases.",
        "entities": [
          {
            "name": "AttendanceRecord",
            "attributes": ["recordId", "date", "checkInTime", "checkOutTime", "status (PRESENT, ABSENT, LATE, EXCUSED)"],
            "businessRules": ["No se puede registrar salida antes de la entrada.", "Solo se puede registrar una entrada y una salida por alumno y por día."]
          }
        ],
        "relationships": ["Student (1) --- (*) AttendanceRecord"]
      },
      {
        "name": "Billing",
        "description": "Gestión de la facturación mensual por conceptos de matrícula y pensión.",
        "entities": [
          {
            "name": "Invoice",
            "attributes": ["invoiceId", "issueDate", "dueDate", "monthYear", "totalAmount", "status (PENDING, PAID, OVERDUE, CANCELLED)", "paymentDate"],
            "businessRules": ["El totalAmount es la suma de los conceptos (InvoiceItem).", "Solo se puede generar una factura por alumno y por mes (monthYear)."]
          },
          {
            "name": "InvoiceItem",
            "attributes": ["itemId", "description", "quantity", "unitPrice", "subtotal"],
            "businessRules": ["El subtotal se calcula como quantity * unitPrice."]
          },
          {
            "name": "Payment",
            "attributes": ["paymentId", "amount", "paymentMethod", "transactionDate", "reference"],
            "businessRules": ["El monto del pago no puede superar el total pendiente de la factura."]
          }
        ],
        "relationships": ["Student (1) --- (*) Invoice", "Invoice (1) --- (*) InvoiceItem", "Invoice (1) --- (*) Payment"]
      },
      {
        "name": "Academic",
        "description": "Información sobre la estructura académica del colegio.",
        "entities": [
          {
            "name": "Grade",
            "attributes": ["gradeId", "name", "level"],
            "businessRules": ["El nombre del grado debe ser único dentro del colegio."]
          },
          {
            "name": "ClassGroup",
            "attributes": ["classGroupId", "academicYear", "section"],
            "businessRules": ["La combinación academicYear, grade y section debe ser única."]
          }
        ],
        "relationships": ["Grade (1) --- (*) ClassGroup", "Student (*) --- (*) ClassGroup (Histórico de matriculaciones)", "ClassGroup (1) --- (*) Student (matrícula actual)"]
      }
    ],
    "sharedKernel": {
      "valueObjects": [
        {
          "name": "Money",
          "attributes": ["amount", "currency"]
        },
        {
          "name": "PersonalName",
          "attributes": ["firstName", "lastName"]
        },
        {
          "name": "DateRange",
          "attributes": ["startDate", "endDate"]
        }
      ],
      "enums": ["StudentStatus", "AttendanceStatus", "InvoiceStatus"]
    },
    "invariantsAndPolicies": [
      "La facturación del mes M solo se habilita si el alumno tuvo al menos un 80% de asistencia en el mes M-1 (Política de Negocio).",
      "Un alumno no puede ser dado de baja si tiene facturas pendientes de pago (Invariante).",
      "El checkOutTime es obligatorio para calcular la asistencia diaria completa."
    ]
  }
}
